INSERT INTO public.enemies (slug, name, source, data) VALUES ('allosaurus','Allosaurus','SRD','{"sizeType":"Large beast, unaligned","armorClass":{"value":13,"note":"natural armor"},"hitPoints":{"average":51,"formula":"6d10+18"},"speed":"60 ft.","abilityScores":{"str":19,"dex":13,"con":17,"int":2,"wis":12,"cha":5},"skills":[{"name":"Perception","bonus":5}],"senses":"passive Perception 15","languages":"","challengeRating":"2","xp":450,"proficiencyBonus":2,"traits":[{"name":"Pounce","description":"If the allosaurus moves at least 30 feet straight toward a creature and then hits it with a claw attack on the same turn, that target must succeed on a DC 13 Strength saving throw or be knocked prone. If the target is prone, the allosaurus can make one bite attack against it as a bonus action."}],"actions":[{"name":"Bite","description":"Melee Weapon Attack: +6 to hit, reach 5 ft., one target. Hit: 15 (2d10 + 4) piercing damage."},{"name":"Claw","description":"Melee Weapon Attack: +6 to hit, reach 5 ft., one target. Hit: 8 (1d8 + 4) slashing damage."}],"description":"The allosaurus is a predatory dinosaur of great size, strength, and speed. It can run down almost any prey over open ground, pouncing to pull creatures down with its wicked claws.","tags":["Beast"],"habitat":"Grassland","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
